18264 template <typename T>
18265 static bool tryToVectorizeSequence(
18266     SmallVectorImpl<T *> &Incoming, function_ref<bool(T *, T *)> Comparator,
18267     function_ref<bool(T *, T *)> AreCompatible,
18268     function_ref<bool(ArrayRef<T *>, bool)> TryToVectorizeHelper,
18269     bool MaxVFOnly, BoUpSLP &R) {
18270   bool Changed = false;
18271   // Sort by type, parent, operands.
18272   stable_sort(Incoming, Comparator);
18273 
18274   // Try to vectorize elements base on their type.
18275   SmallVector<T *> Candidates;
18276   SmallVector<T *> VL;
18277   for (auto *IncIt = Incoming.begin(), *E = Incoming.end(); IncIt != E;
18278        VL.clear()) {
18279     // Look for the next elements with the same type, parent and operand
18280     // kinds.
18281     auto *I = dyn_cast<Instruction>(*IncIt);
18282     if (!I || R.isDeleted(I)) {
18283       ++IncIt;
18284       continue;
18285     }
18286     auto *SameTypeIt = IncIt;
18287     while (SameTypeIt != E && (!isa<Instruction>(*SameTypeIt) ||
18288                                R.isDeleted(cast<Instruction>(*SameTypeIt)) ||
18289                                AreCompatible(*SameTypeIt, *IncIt))) {
18290       auto *I = dyn_cast<Instruction>(*SameTypeIt);
18291       ++SameTypeIt;
18292       if (I && !R.isDeleted(I))
18293         VL.push_back(cast<T>(I));
18294     }
18295 
18296     // Try to vectorize them.
18297     unsigned NumElts = VL.size();
18298     LLVM_DEBUG(dbgs() << "SLP: Trying to vectorize starting at nodes ("
18299                       << NumElts << ")\n");
18300     // The vectorization is a 3-state attempt:
18301     // 1. Try to vectorize instructions with the same/alternate opcodes with the
18302     // size of maximal register at first.
18303     // 2. Try to vectorize remaining instructions with the same type, if
18304     // possible. This may result in the better vectorization results rather than
18305     // if we try just to vectorize instructions with the same/alternate opcodes.
18306     // 3. Final attempt to try to vectorize all instructions with the
18307     // same/alternate ops only, this may result in some extra final
18308     // vectorization.
18309     if (NumElts > 1 && TryToVectorizeHelper(ArrayRef(VL), MaxVFOnly)) {
18310       // Success start over because instructions might have been changed.
18311       Changed = true;
18312       VL.swap(Candidates);
18313       Candidates.clear();
18314       for (T *V : VL) {
18315         if (auto *I = dyn_cast<Instruction>(V); I && !R.isDeleted(I))
18316           Candidates.push_back(V);
18317       }
18318     } else {
18319       /// \Returns the minimum number of elements that we will attempt to
18320       /// vectorize.
18321       auto GetMinNumElements = [&R](Value *V) {
18322         unsigned EltSize = R.getVectorElementSize(V);
18323         return std::max(2U, R.getMaxVecRegSize() / EltSize);
18324       };
18325       if (NumElts < GetMinNumElements(*IncIt) &&
18326           (Candidates.empty() ||
18327            Candidates.front()->getType() == (*IncIt)->getType())) {
18328         for (T *V : VL) {
18329           if (auto *I = dyn_cast<Instruction>(V); I && !R.isDeleted(I))
18330             Candidates.push_back(V);
18331         }
18332       }
18333     }
18334     // Final attempt to vectorize instructions with the same types.
18335     if (Candidates.size() > 1 &&
18336         (SameTypeIt == E || (*SameTypeIt)->getType() != (*IncIt)->getType())) {
18337       if (TryToVectorizeHelper(Candidates, /*MaxVFOnly=*/false)) {
18338         // Success start over because instructions might have been changed.
18339         Changed = true;
18340       } else if (MaxVFOnly) {
18341         // Try to vectorize using small vectors.
18342         SmallVector<T *> VL;
18343         for (auto *It = Candidates.begin(), *End = Candidates.end(); It != End;
18344              VL.clear()) {
18345           auto *I = dyn_cast<Instruction>(*It);
18346           if (!I || R.isDeleted(I)) {
18347             ++It;
18348             continue;
18349           }
18350           auto *SameTypeIt = It;
18351           while (SameTypeIt != End &&
18352                  (!isa<Instruction>(*SameTypeIt) ||
18353                   R.isDeleted(cast<Instruction>(*SameTypeIt)) ||
18354                   AreCompatible(*SameTypeIt, *It))) {
18355             auto *I = dyn_cast<Instruction>(*SameTypeIt);
18356             ++SameTypeIt;
18357             if (I && !R.isDeleted(I))
18358               VL.push_back(cast<T>(I));
18359           }
18360           unsigned NumElts = VL.size();
18361           if (NumElts > 1 && TryToVectorizeHelper(ArrayRef(VL),
18362                                                   /*MaxVFOnly=*/false))
18363             Changed = true;
18364           It = SameTypeIt;
18365         }
18366       }
18367       Candidates.clear();
18368     }
18369 
18370     // Start over at the next instruction of a different type (or the end).
18371     IncIt = SameTypeIt;
18372   }
18373   return Changed;
18374 }
