18376 /// Compare two cmp instructions. If IsCompatibility is true, function returns
18377 /// true if 2 cmps have same/swapped predicates and mos compatible corresponding
18378 /// operands. If IsCompatibility is false, function implements strict weak
18379 /// ordering relation between two cmp instructions, returning true if the first
18380 /// instruction is "less" than the second, i.e. its predicate is less than the
18381 /// predicate of the second or the operands IDs are less than the operands IDs
18382 /// of the second cmp instruction.
18383 template <bool IsCompatibility>
18384 static bool compareCmp(Value *V, Value *V2, TargetLibraryInfo &TLI,
18385                        const DominatorTree &DT) {
18386   assert(isValidElementType(V->getType()) &&
18387          isValidElementType(V2->getType()) &&
18388          "Expected valid element types only.");
