18390     return IsCompatibility;
18391   auto *CI1 = cast<CmpInst>(V);
18392   auto *CI2 = cast<CmpInst>(V2);
18393   if (CI1->getOperand(0)->getType()->getTypeID() <
18394       CI2->getOperand(0)->getType()->getTypeID())
18395     return !IsCompatibility;
18396   if (CI1->getOperand(0)->getType()->getTypeID() >
18397       CI2->getOperand(0)->getType()->getTypeID())
18398     return false;
18399   CmpInst::Predicate Pred1 = CI1->getPredicate();
18400   CmpInst::Predicate Pred2 = CI2->getPredicate();
18401   CmpInst::Predicate SwapPred1 = CmpInst::getSwappedPredicate(Pred1);
18402   CmpInst::Predicate SwapPred2 = CmpInst::getSwappedPredicate(Pred2);
18403   CmpInst::Predicate BasePred1 = std::min(Pred1, SwapPred1);
18404   CmpInst::Predicate BasePred2 = std::min(Pred2, SwapPred2);
18405   if (BasePred1 < BasePred2)
18406     return !IsCompatibility;
18407   if (BasePred1 > BasePred2)
18408     return false;
18409   // Compare operands.
18410   bool CI1Preds = Pred1 == BasePred1;
18411   bool CI2Preds = Pred2 == BasePred1;
18412   for (int I = 0, E = CI1->getNumOperands(); I < E; ++I) {
18413     auto *Op1 = CI1->getOperand(CI1Preds ? I : E - I - 1);
18414     auto *Op2 = CI2->getOperand(CI2Preds ? I : E - I - 1);
18415     if (Op1 == Op2)
18416       continue;
18417     if (Op1->getValueID() < Op2->getValueID())
18418       return !IsCompatibility;
18419     if (Op1->getValueID() > Op2->getValueID())
18420       return false;
18421     if (auto *I1 = dyn_cast<Instruction>(Op1))
18422       if (auto *I2 = dyn_cast<Instruction>(Op2)) {
18423         if (IsCompatibility) {
18424           if (I1->getParent() != I2->getParent())
18425             return false;
18426         } else {
18427           // Try to compare nodes with same parent.
18428           DomTreeNodeBase<BasicBlock> *NodeI1 = DT.getNode(I1->getParent());
18429           DomTreeNodeBase<BasicBlock> *NodeI2 = DT.getNode(I2->getParent());
18430           if (!NodeI1)
18431             return NodeI2 != nullptr;
18432           if (!NodeI2)
18433             return false;
18434           assert((NodeI1 == NodeI2) ==
18435                      (NodeI1->getDFSNumIn() == NodeI2->getDFSNumIn()) &&
18436                  "Different nodes should have different DFS numbers");
18437           if (NodeI1 != NodeI2)
18438             return NodeI1->getDFSNumIn() < NodeI2->getDFSNumIn();
18439         }
18440         InstructionsState S = getSameOpcode({I1, I2}, TLI);
18441         if (S.getOpcode() && (IsCompatibility || !S.isAltShuffle()))
18442           continue;
18443         if (IsCompatibility)
18444           return false;
18445         if (I1->getOpcode() != I2->getOpcode())
18446           return I1->getOpcode() < I2->getOpcode();
18447       }
18448   }
18449   return IsCompatibility;
18450 }
