17750   /// Emits optimized code for unique scalar value reused \p Cnt times.
17751   Value *emitScaleForReusedOps(Value *VectorizedValue, IRBuilderBase &Builder,
17752                                unsigned Cnt) {
17753     assert(IsSupportedHorRdxIdentityOp &&
17754            "The optimization of matched scalar identity horizontal reductions "
17755            "must be supported.");
17756     switch (RdxKind) {
17757     case RecurKind::Add: {
17758       // res = mul vv, n
17759       Value *Scale = ConstantInt::get(VectorizedValue->getType(), Cnt);
