17761                         << VectorizedValue << ". (HorRdx)\n");
17762       return Builder.CreateMul(VectorizedValue, Scale);
17763     }
17764     case RecurKind::Xor: {
17765       // res = n % 2 ? 0 : vv
17766       LLVM_DEBUG(dbgs() << "SLP: Xor " << Cnt << "of " << VectorizedValue
17767                         << ". (HorRdx)\n");
17768       if (Cnt % 2 == 0)
17769         return Constant::getNullValue(VectorizedValue->getType());
17770       return VectorizedValue;
17771     }
17772     case RecurKind::FAdd: {
17773       // res = fmul v, n
17774       Value *Scale = ConstantFP::get(VectorizedValue->getType(), Cnt);
17775       LLVM_DEBUG(dbgs() << "SLP: FAdd (to-fmul) " << Cnt << "of "
17776                         << VectorizedValue << ". (HorRdx)\n");
17777       return Builder.CreateFMul(VectorizedValue, Scale);
17778     }
17779     case RecurKind::And:
17780     case RecurKind::Or:
17781     case RecurKind::SMax:
17782     case RecurKind::SMin:
17783     case RecurKind::UMax:
17784     case RecurKind::UMin:
17785     case RecurKind::FMax:
17786     case RecurKind::FMin:
17787     case RecurKind::FMaximum:
17788     case RecurKind::FMinimum:
17789       // res = vv
17790       return VectorizedValue;
17791     case RecurKind::Mul:
17792     case RecurKind::FMul:
17793     case RecurKind::FMulAdd:
17794     case RecurKind::IAnyOf:
17795     case RecurKind::FAnyOf:
17796     case RecurKind::None:
17797       llvm_unreachable("Unexpected reduction kind for repeated scalar.");
17798     }
17799     return nullptr;
17800   }
