14493 void BoUpSLP::BlockScheduling::cancelScheduling(ArrayRef<Value *> VL,
14494                                                 Value *OpValue) {
14495   if (isa<PHINode>(OpValue) || isVectorLikeInstWithConstOps(OpValue) ||
14496       doesNotNeedToSchedule(VL))
14497     return;
14498 
14499   if (doesNotNeedToBeScheduled(OpValue))
14500     OpValue = *find_if_not(VL, doesNotNeedToBeScheduled);
14501   ScheduleData *Bundle = getScheduleData(OpValue);
14502   LLVM_DEBUG(dbgs() << "SLP:  cancel scheduling of " << *Bundle << "\n");
14503   assert(!Bundle->IsScheduled &&
14504          "Can't cancel bundle which is already scheduled");
14505   assert(Bundle->isSchedulingEntity() &&
14506          (Bundle->isPartOfBundle() || needToScheduleSingleInstruction(VL)) &&
14507          "tried to unbundle something which is not a bundle");
14508 
14509   // Remove the bundle from the ready list.
14510   if (Bundle->isReady())
14511     ReadyInsts.remove(Bundle);
14512 
14513   // Un-bundle: make single instructions out of the bundle.
14514   ScheduleData *BundleMember = Bundle;
14515   while (BundleMember) {
14516     assert(BundleMember->FirstInBundle == Bundle && "corrupt bundle links");
14517     BundleMember->FirstInBundle = BundleMember;
14518     ScheduleData *Next = BundleMember->NextInBundle;
14519     BundleMember->NextInBundle = nullptr;
14520     BundleMember->TE = nullptr;
14521     if (BundleMember->unscheduledDepsInBundle() == 0) {
14522       ReadyInsts.insert(BundleMember);
14523     }
14524     BundleMember = Next;
14525   }
14526 }
